dslRule:
/*!id: jdt-internal-unnamedclass-to-implicittypedeclaration*/
/*!description: Rename internal JDT AST type from UnnamedClass to ImplicitTypeDeclaration in instanceof expressions. This reflects internal API modernization for unnamed classes/implicit types (JEP 445).*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring*/

$expression instanceof org.eclipse.jdt.internal.compiler.ast.UnnamedClass $var
=> $expression instanceof org.eclipse.jdt.internal.compiler.ast.ImplicitTypeDeclaration $var
;;
